INSERT INTO public.photos VALUES (24785, '&quot;Geplasmetal&quot; c.1990', 'Imagen en altura desde el nâ”¬â•‘ 7-9 de la calle Antonio Tramullas (antiguo Camino de Juslibol) del abandonado complejo industrial de "Geplasmetal" en el Picarral. Esta empresa fue creada en 1958, en el entonces extrarradio de la ciudad, y dedicada a la estampaciâ”śâ”‚n metâ”śĂ­lica e inyecciâ”śâ”‚n de plâ”śĂ­sticos. En los aâ”śâ–’os 60 la empresa creciâ”śâ”‚ y diversificâ”śâ”‚ producciâ”śâ”‚n, y al principio de los aâ”śâ–’os 80, la crisis del sector desembocâ”śâ”‚ en su cierre y traslado al Polâ”śÂˇgono de Cogullada, y al de Malpica. En la imagen, aspecto aâ”śÂ®reo de Geplasmetal, entre la calle de Somport (a la derecha, junto al "Grupo de Viviendas Francisco Franco"), Monte Perdido (al frente), y la calle Antonio Tramullas (en primer plano). A la izquierda, el alabeado linde con la tradicional transformadora industrial del maâ”śÂˇz "Campo Ebro", actual Tereos Syral, que sigue marcando impronta en el barrio. El enruinado solar de Geplasmetal luego fue urbanizado, y todavâ”śÂˇa queda una "pastilla" libre. Fuente visual: Banco de Imâ”śĂ­genes Picarral fotosdelpicarral.blogspot.com.es/', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.67500500, -0.87374400, '0101000020E61000006D7022FAB5F5EBBF78D1579066D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30006637060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30006637060.webp', 'https://www.flickr.com/photos/zaragozaantigua/30006637060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24786, '&quot;TUSA&quot; 1990', 'Imagen previa a la voladura controlada de los edificios principales de la empresa "Talleres Unidos S.A." (TUSA) del Picarral. Creada en 1956 como una de las numerosas empresas metalâ”śâ•‘rgicas que entonces se radicaban en esa zona de la ciudad, en 1965 fue absorbida por la francesa Proclain. Llegâ”śâ”‚ a tener algo mâ”śĂ­s de 1000 trabajadores, y fue la sâ”śÂ®ptima empresa del sector del metal de la provincia. La crisis del sector en el principio de los aâ”śâ–’os 80 terminâ”śâ”‚ con su cierre en 1984, previo acuerdo con la plantilla. Un par de aâ”śâ–’os despuâ”śÂ®s, una nueva "TUSA" (ahora Transportadores Universales S.A.) surgiâ”śâ”‚ en Malpica, de dimensiones mucho mâ”śĂ­s reducidas, que perdura. En la imagen, aspecto de la achaflanada fachada principal de la fâ”śĂ­brica ubicada en el Camino de Juslibol. A la derecha, la calle Monte Perdido, y al fondo, bloques de la Avenida de Salvador Allende. Sobre el enorme solar resultante poco despuâ”śÂ®s se construirâ”śÂˇan varias docenas de adosados, y en el edificio de la fotografâ”śÂˇa serâ”śÂˇa reivindicada vecinalmente una plaza que, denominada Juan Acha en recuerdo a un sacerdote de la vecina parroquia de Belâ”śÂ®n, serâ”śÂˇa inaugurada en 2005. Fuente visual: Banco de Imâ”śĂ­genes Picarral fotosdelpicarral.blogspot.com.es/', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.67082200, -0.87301400, '0101000020E610000094675E0EBBEFEBBFFAB7CB7EDDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30266919286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30266919286.webp', 'https://www.flickr.com/photos/zaragozaantigua/30266919286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24802, 'Arrabal 1977', 'Imagen capturada desde la altura del paso para trâ”śĂ­fico rodado de la avenida Alcalde Caballero sobre el mar de vâ”śÂˇas y cargadero del Arrabal, y los apartaderos ferroviarios (centro de la imagen) en el entorno a las importantes empresas Fundiciâ”śâ”‚n Rico y Echevarrâ”śÂˇa, y la papelera SAICA. Al fondo, entre las emanaciones fabriles, una torre del Pilar, y la torre y cimborrio de la Seo. A la izquierda, polâ”śÂˇgono industrial Alcalde Caballero. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67422800, -0.86544000, '0101000020E6100000C4CE143AAFB1EBBF1406651A4DD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33220625882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33220625882.webp', 'https://www.flickr.com/photos/zaragozaantigua/33220625882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24803, 'Avenida Cataluâ”śâ–’a 2010', 'Foto: Pedro Etura. El 26 de octubre de 2010, la primera unidad del nuevo tranvâ”śÂˇa de Zaragoza fue transportada desde la factorâ”śÂˇa de Construcciones y Auxiliar de Ferrocarriles (CAF), en la avenida de Cataluâ”śâ–’a 299, hasta las cocheras de Valdespartera. Se trata del modelo Urbos 3. El 19 de abril de 2011 se inaugurâ”śâ”‚ la primera fase de la lâ”śÂˇnea 1. En la foto, al fondo, el Pilar, con sus dos torres norte en restauraciâ”śâ”‚n. A la derecha, el bloque de la avenida de Cataluâ”śâ–’a 253. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'EL RABAL', 41.67060800, -0.84497300, '0101000020E6100000A41820D1040AEBBFCE37A27BD6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33387254830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33387254830.webp', 'https://www.flickr.com/photos/zaragozaantigua/33387254830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24807, 'Azucarera del Gâ”śĂ­llego 1931', 'Vista general del complejo fabril de la Azucarera del Gâ”śĂ­llego, entre la carretera de Barcelona (a la izquierda, fuera de plano), el camino de Valimaâ”śâ–’a (a la derecha, fuera de plano) y el râ”śÂˇo Gâ”śĂ­llego (al fondo). Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”śâ–’o y admiraciâ”śâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34372598115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34372598115.webp', 'https://www.flickr.com/photos/zaragozaantigua/34372598115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24809, 'Camino de la Corbera 1977', 'Vista aâ”śÂ®rea de la factorâ”śÂˇa de la empresa Usâ”śâ”‚n S.A. en el camino de la Corbera Baja, donde se producâ”śÂˇan hierros, aceros, ferreterâ”śÂˇa y maquinaria. Esta empresa habâ”śÂˇa sido fundada en 1790, y en las primeras dâ”śÂ®cadas del siglo XX estaba ubicada, como Antonio Usâ”śâ”‚n, y luego Viuda e Hijos de Antonio Usâ”śâ”‚n, en la avenida de Madrid, con acceso ferroviario a la estaciâ”śâ”‚n de Campo Sepulcro. Aâ”śâ–’os despuâ”śÂ®s, en la ubicaciâ”śâ”‚n de la imagen se situâ”śâ”‚ la empresa Vehizasa. Al norte de la factorâ”śÂˇa circula la carretera de los enlaces, que aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇa denominada avenida de Salvador Allende. A la derecha, enlace con el complejo ferroviario de Arrabal mercancâ”śÂˇas. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67525300, -0.86639500, '0101000020E61000009A5FCD0182B9EBBF50C3B7B06ED64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34799586745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34799586745.webp', 'https://www.flickr.com/photos/zaragozaantigua/34799586745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24810, 'Puente sobre el Gâ”śĂ­llego 1929', 'Imagen capturada desde la margen izquierda izquierda del râ”śÂˇo Gâ”śĂ­llego, y centrada en el estado de la obra de construcciâ”śâ”‚n del nuevo puente tendido entre el desaparecido puente medieval (restos a la derecha), y el veterano puente colgante (a la izquierda), que serâ”śÂˇa desmantelado una vez entrara en servicio el metâ”śĂ­lico nuevo puente. Se trataba de una obra importante, en la estratâ”śÂ®gica carretera nacional de Madrid a Francia. La obra comenzâ”śâ”‚ en 1926 con diseâ”śâ–’o de Primitivo Sagasta, ingeniero de la Jefatura de Obras pâ”śâ•‘blicas de Zaragoza, y en el momento de realizar la imagen estaban bien finalizados los cimientos y alzados, si bien las partes metâ”śĂ­licas sufrâ”śÂˇan un notable retraso que dilatarâ”śÂˇa su inauguraciâ”śâ”‚n y apertura al trâ”śĂ­nsito hasta 1930. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34836131120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34836131120.webp', 'https://www.flickr.com/photos/zaragozaantigua/34836131120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25416, 'Puente sobre el Gâ”śĂ­llego c.1924', 'Imagen del puente colgante sobre el râ”śÂˇo Gâ”śĂ­llego, pero desde abajo, junto a la ribera de este râ”śÂˇo. Por encima, el camino de Barcelona supera esta trinchera, y llega al barrio de Santa Isabel, al fondo. Al poco (1927), este puente serâ”śÂˇa sustituido por otro mâ”śĂ­s resistente (el actual), porque el Gâ”śĂ­llego cada cierto tiempo bajaba con aguas turbulentas que afectaban mucho tambiâ”śÂ®n a los sucesivos puentes que aquâ”śÂˇ se fueron habilitando. Fuente: Instituto Amatller de Arte Hispâ”śĂ­nico (Arxiu Mas).', 1924, 1924, 1924, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704095408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704095408.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704095408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25436, 'Puente de Santa Isabel c.1920', 'Puente del Santa Isabel sobre el râ”śÂˇo Gâ”śĂ­llego. Al fondo, el barrio de Santa Isabel. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24821682231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24821682231.webp', 'https://www.flickr.com/photos/zaragozaantigua/24821682231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25438, 'Puente de Santa Isabel c.1920', 'Paso de ganado ovino ante el puente de Santa Isabel sobre el râ”śÂˇo Gâ”śĂ­llego. Al fondo, el barrio de Santa Isabel. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24914639425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24914639425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24914639425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25454, 'Ribera del Gâ”śĂ­llego c.1920', 'Imagen capturada en la ribera del râ”śÂˇo Gâ”śĂ­llego mientras un rebaâ”śâ–’o de cabras pasa junto a la arcada superviviente del antiguo puente medieval de piedra del camino de Madrid a Barcelona. Al fondo, depâ”śâ”‚sitos de la azucarera del Gâ”śĂ­llego. El puente colgante sobre el râ”śÂˇo queda hacia la derecha, fuera de plano, y por donde asciende el pastor serâ”śĂ­ construido unos aâ”śâ–’os despuâ”śÂ®s el nuevo puente de hierro que vendrâ”śÂˇa a sustituirlo. Fuente visual: colecciâ”śâ”‚n Jesâ”śâ•‘s Corman, en AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67127100, -0.84260900, '0101000020E6100000A5164A26A7F6EABF69E04735ECD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40141577071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40141577071.webp', 'https://www.flickr.com/photos/zaragozaantigua/40141577071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25901, 'Trolebuses 1954', 'Imagen de la inauguraciâ”śâ”‚n del nuevo servicio de trolebuses de la linea "Gâ”śĂ­llego", entre el Coso, esquina calle de Blancas, y hasta el puente del Gâ”śĂ­llego. La captura se ha realizado en el final de lâ”śÂˇnea, en la avenida de Cataluâ”śâ–’a. Las mâ”śĂ­quinas estâ”śĂ­n recibiendo una bendiciâ”śâ”‚n conforme a la ortodoxia cristiana catâ”śâ”‚lica por parte del pâ”śĂ­rroco de Altabâ”śĂ­s, Pedro Martâ”śÂˇnez. El alcalde, Luis Gâ”śâ”‚mez Laguna, con gafas de sol. A su izquierda, altâ”śÂˇsimo y entrevâ”śÂˇas, el seâ”śâ–’or gobernador givil de la provincia, Josâ”śÂ® Manuel Pardo de Santayana. A su derecha, el gobernador militar, general Arteaga. Fuente visual: â”śĂĽngel de Uâ”śâ–’a, "Luis Gâ”śâ”‚mez Laguna", DGA, 1993.', 1954, 1954, 1954, 'Anos 50', 'EL RABAL', 41.67100400, -0.84390800, '0101000020E610000009A69A594B01EBBF1BBE8575E3D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318260688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318260688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318260688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25917, 'San Juan de la Peâ”śâ–’a 1969', 'Excepcional imagen capturada desde el interior de una de las cinco unidades de los tranvâ”śÂˇas articulados (serie 251-255), que prestaban servicio en la lâ”śÂˇnea 10 "Academia", un poco antes de cruzarse con la unidad 254. Posiblemente, el escenario sea la calle de San Juan de la Peâ”śâ–’a, direcciâ”śâ”‚n AGM, poco despuâ”śÂ®s del arranque del camino de los Molinos, y tras haber pasado junto a "Coromina Industrial". A la izquierda, viviendas inmediatas a Campo Ebro Industrial. Tras la clausura de esta lâ”śÂˇnea, en enero de 1971, las cinco unidades referidas fueron desguazadas. El conductor, al mando del regulador que controlaba la marcha y frenado del tranvâ”śÂˇa. Destaca la caracterâ”śÂˇstica manivela. Fuente visual: Foto John Scragg, a travâ”śÂ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'EL RABAL', 41.67500500, -0.87120100, '0101000020E610000087C267EBE0E0EBBF78D1579066D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31030868792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31030868792.webp', 'https://www.flickr.com/photos/zaragozaantigua/31030868792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26001, 'Azucarera Gâ”śĂ­llego 1957', 'Vista en altura del complejo fabril de la Azucarera del Gâ”śĂ­llego, entre la carretera de Barcelona, en primer plano, y el camino de Valimaâ”śâ–’a y el râ”śÂˇo Gâ”śĂ­llego al fondo. Muy cerca, a la izquierda, queda el puente de Santa Isabel, de acceso al barrio del mismo nombre, visible al otro lado del râ”śÂˇo. Movera, a la derecha. Fuente: Foto Marâ”śÂˇn Chivite.', 1957, 1957, 1957, 'Anos 50', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21943727798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21943727798.webp', 'https://www.flickr.com/photos/zaragozaantigua/21943727798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26018, 'Râ”śÂˇo Gâ”śĂ­llego 1974', 'Imagen en altura desde los recientes bloques de viviendas cercanos al puente del râ”śÂˇo Gâ”śĂ­llego, ya en el barrio de Santa Isabel, con una panorâ”śĂ­mica vista dirigiendo el objetivo hacia la ciudad. En primer tâ”śÂ®rmino, el râ”śÂˇo. En la margen derecha, el solar donde estuviera la Azucarera del Gâ”śĂ­llego entre 1913 y 1967. Detrâ”śĂ­s, la carretera de Barcelona como uno de los nuevos ejes de desarrollo industrial, y algâ”śâ•‘n extraâ”śâ–’o bloque de viviendas en medio de la nada. El "ferroducto" sobre la huerta antecede a los primeros megabloques de Vadorrey. Al fondo, chimeneas (azucarera del Arrabal) y torres (Pilar, Seo...) anuncian a la vieja ciudad. Fuente: Gerardo Sancho Ramo (Archivo Pâ”śâ•‘blico Municipal).', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66990800, -0.84194400, '0101000020E61000009207228B34F1EABF15AA9B8BBFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23860348119.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23860348119.webp', 'https://www.flickr.com/photos/zaragozaantigua/23860348119/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26072, 'Picarral 1955', 'Vista aâ”śÂ®rea del Picarral sobrevolando el entorno de las instalaciones del Consorcio Agrâ”śÂˇcola Industrial Textil Aragonâ”śÂ®s, S.A., Caitasa, que en esta imagen queda en segundo plano, tras el camino de Juslibol. En primer tâ”śÂ®rmino, el pionero bloque de viviendas de la primera fase del Grupo de Viviendas "Francisco Franco", en esta despejada y agrâ”śÂˇcola zona del Picarral delimitada entre el camino de Juslibol, el brazal del Canal de Piedra del escorredero de Juslibol, y la carretera de Huesca, que aquâ”śÂˇ queda a la izquierda y fuera de plano. Este bloque fue proyectado por los arquitectos Josâ”śÂ® de Yarza y Josâ”śÂ® Beltrâ”śĂ­n, y constaba de 120 viviendas de 45 a 50 m2, modestas porque sus habitantes serâ”śÂˇan familias de trabajadores, y 8 tiendas con acceso por la nueva calle de Anzâ”śĂ­nigo. Aunque este bloque fue terminado en 1949, sâ”śâ”‚lo empezâ”śâ”‚ a ser ocupado en 1952. Los otros bloques del grupo serâ”śÂˇan construido a partir de 1957, y este entorno comenzarâ”śÂˇa entonces a transformarse radicalmente.', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.67429800, -0.87362700, '0101000020E610000009E23C9CC0F4EBBF0DE198654FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50839765593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50839765593.webp', 'https://www.flickr.com/photos/zaragozaantigua/50839765593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21023, 'Balsas de Ebro Viejo 1867', '"Plano topogrâ”śĂ­fico de las balsas denominadas de Ebro biejo y proyecto para su desecaciâ”śâ”‚n", Segundo Dâ”śÂˇaz, Zaragoza, 20 de julio de 1867. Plano de la Margen Izquierda de Zaragoza, orientado con el norte a la derecha. Se inicia en el puente de Piedra (abajo a la izquierda). Mâ”śĂ­s arriba el escorredero principal de las balsas de Ebro viejo, antes de llegar a la arboleda de Macanaz. La representaciâ”śâ”‚n grâ”śĂ­fica limita al norte con el camino de la Hortilla y al sur con el de Juslibol. Fuente: AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'EL RABAL', 41.66026200, -0.87538900, '0101000020E61000008EE6C8CA2F03ECBF5265187783D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21039158291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21039158291.webp', 'https://www.flickr.com/photos/zaragozaantigua/21039158291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21196, 'Lavandera c.1890', 'â”śĂ´leo titulado "Lavandera a las afueras de Zaragoza" realizado por Joaquâ”śÂˇn Pallarâ”śÂ®s y Allustante durante su etapa como profesor de "Dibujo del Antiguo" de la Escuela de Bellas Artes, y a la vez conservador de los fondos pictâ”śâ”‚ricos del Museo Provincial en el antiguo convento de Santa Fe. El fondo reconocible de las torres de Santa Marâ”śÂˇa Magdalena, de la Seo, y de la inconclusa de Santiago del templo del Pilar, nos sitâ”śâ•‘a probablemente en el entorno del râ”śÂˇo Gâ”śĂ­llego.', 1890, 1890, 1890, 'Siglo XIX', 'EL RABAL', 41.66268500, -0.84556100, '0101000020E6100000E0BC38F1D50EEBBF5F46B1DCD2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50973718003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50973718003.webp', 'https://www.flickr.com/photos/zaragozaantigua/50973718003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21213, 'Estaciâ”śâ”‚n del Norte 1900', 'Equipo laboral de la estaciâ”śâ”‚n ferroviaria del Norte o Arrabal, en 1900. Habâ”śÂˇa sido inaugurada en 1861. Fuente visual: Archivo Asociaciâ”śâ”‚n de vecinos Tâ”śÂˇo Jorge Arrabal, en Cristina Mâ”¬Â¬ Palacio Jaâ”śÂ®n, El re-uso de la arquitectura industrial: a propâ”śâ”‚sito de las harineras, fundiciones y azucareras en Aragâ”śâ”‚n en el cambio de siglo, Universidad de Zaragoza, 2013.', 1900, 1900, 1900, 'Anos 1900', 'EL RABAL', 41.66012000, -0.87145900, '0101000020E610000072C119FCFDE2EBBFBFB7E9CF7ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15037805385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15037805385.webp', 'https://www.flickr.com/photos/zaragozaantigua/15037805385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21412, 'Nueva Harinera 1913', 'En 1910 fue constituida la sociedad "Hijos y sobrino de Juan Solans (Lerâ”śÂˇn)", que construyâ”śâ”‚ la fâ”śĂ­brica "Nueva Harinera" en la calle Arrabal nâ”¬â•‘ 260, junto a la carretera de Barcelona y la estaciâ”śâ”‚n de ferrocarril Norte, con apartadero propio. Muy cerca, con diseâ”śâ–’o de Miguel â”śĂĽngel Navarro, fue construido un "hotel", o villa, del propietario harinero, Juan Solans. Esta harinera era, por su capacidad productiva, la mayor de la ciudad. Pocos aâ”śâ–’os despuâ”śÂ®s de la muerte de Juan Solans (1926), en 1931 una nueva sociedad capitalista (Harinas Solans, S.A.) se hizo con las riendas de esta harinera, que fue redenominada "Harinas Solans". Estuvo activa hasta su cierre en 1985. En 1998 fue derribada, y el entorno reurbanizado. Fuente visual: "Heraldo de Madrid", octubre 1913.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27907331021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27907331021.webp', 'https://www.flickr.com/photos/zaragozaantigua/27907331021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21653, 'Balsas de Ebro Viejo 1923', 'Imagen capturada en las Balsas de Ebro Viejo con un entraâ”śâ–’able posado del castizo y tradicionalista poeta Alberto Casaâ”śâ–’al Shakery con motivo de su doble reconocimiento municipal tras la imposiciâ”śâ”‚n de la Medalla de Oro de la ciudad y la entrega del tâ”śÂˇtulo de Hijo Adoptivo. Al fondo, como no podâ”śÂˇa ser de otra forma, el templo del Pilar al otro lado del Ebro.', 1923, 1923, 1923, 'Anos 20', 'EL RABAL', 41.66231600, -0.87684600, '0101000020E6100000FC1BB4571F0FECBF0BCF4BC5C6D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52130179262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52130179262.webp', 'https://www.flickr.com/photos/zaragozaantigua/52130179262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21661, 'Arrabal 1921', 'Fotograma de un reportaje realizado durante el breve paso por Zaragoza del Ministro de Fomento Juan de la Cierva Peâ”śâ–’afiel a principios de junio de ese aâ”śâ–’o y centrado en la visita a la Nueva Harinera de Hijos y Sobrino de Solans sita en el Arrabal, en las traseras del depâ”śâ”‚sito de locomotoras de la Estaciâ”śâ”‚n del Norte. Aquâ”śÂˇ figura Juan Solans Solans (sobrino del fundador de la empresa precedente Juan Solans Lerâ”śÂˇn), tras el caballero que seâ”śâ–’ala al ministro varios montones de harina procesada en la fâ”śĂ­brica segâ”śâ•‘n distintos tipos de molienda. A su paso por la ciudad el ministro fue acompaâ”śâ–’ado en todo momento por sus fervientes partidarios del "comitâ”śÂ® ciervista de Zaragoza", câ”śÂ®lula local de la facciâ”śâ”‚n polâ”śÂˇtica considerada de extrema derecha dentro del conservadurismo autoritario, que bajo la etiqueta de "Conservadores ciervistas" por el apellido de este polâ”śÂˇtico murciano, en las elecciones a Cortes de diciembre del aâ”śâ–’o anterior habâ”śÂˇa logrado 23 diputados en todo el paâ”śÂˇs.', 1921, 1921, 1921, 'Anos 20', 'EL RABAL', 41.66152300, -0.86935700, '0101000020E6100000B98E71C5C5D1EBBFA24621C9ACD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54691566687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54691566687.webp', 'https://www.flickr.com/photos/zaragozaantigua/54691566687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21947, 'Estaciâ”śâ”‚n del Norte c.1940', 'Imagen, con el telâ”śâ”‚n de fondo de las torres de la Seo, Altabâ”śĂ­s, y el Pilar, de buena parte del complejo ferroviario de la antigua estaciâ”śâ”‚n del Norte, que fuera la primera inaugurada de la ciudad, en 1861. El â”śâ•‘ltimo tren de pasajeros circulâ”śâ”‚ por aquâ”śÂˇ en los aâ”śâ–’os 70 del pasado siglo, quedando unos aâ”śâ–’os como terminal de mercancâ”śÂˇas, hasta su clausura a principios de los aâ”śâ–’os 80. Desde diciembre de 2004 uno de los dos edificios principales de la estaciâ”śâ”‚n del Norte (el de al izquierda de la imagen) funciona como centro câ”śÂˇvico "Estaciâ”śâ”‚n del Norte" del Arrabal. Fuente visual: Fundaciâ”śâ”‚n de los Ferrocarriles Espaâ”śâ–’oles.', 1940, 1940, 1940, 'Anos 40', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16370172684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16370172684.webp', 'https://www.flickr.com/photos/zaragozaantigua/16370172684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22164, 'Arrabal 1958', 'Aâ”śÂ®rea visual de la Maquinista y Fundiciones del Ebro, S.A. tras la ampliaciâ”śâ”‚n acometida en los aâ”śâ–’os 50, donde se construyeron algunos de sus mâ”śĂ­s representativos edificios, hasta su derribo: el gran almacâ”śÂ®n de modelos con su referente torre, y las grandes naves de fundiciâ”śâ”‚n y caldererâ”śÂˇa. Bajo ellas, andamios para levantar las nuevas naves de montaje. Los nuevos edificios destacan de los anteriores, por su escala. A la izquierda de la fâ”śĂ­brica, vâ”śÂˇas y depâ”śâ”‚sito de locomotoras de la estaciâ”śâ”‚n del Norte. Al norte, la Nueva Harinera de Solans, y los primeros depâ”śâ”‚sitos de remolacha de la azucarera del Arrabal, cuyos edificios principales y chimeneas quedan fuera de plano. Fuente visual: aportaciâ”śâ”‚n personal de Arturo Bressel Viâ”śâ–’uales.', 1958, 1958, 1958, 'Anos 50', 'EL RABAL', 41.66099500, -0.87094900, '0101000020E6100000247CEF6FD0DEEBBFE6E8F17B9BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30819725756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30819725756.webp', 'https://www.flickr.com/photos/zaragozaantigua/30819725756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22353, 'Alcoholera Ebro 1960', 'Alcoholera del Arrabal en una imagen de sus pequeâ”śâ–’as instalaciones fabriles ubicadas frente al â”śĂ­rea sur del Polâ”śÂˇgono Ebro Viejo. Fue fundada en 1911 como Azucarera del Ebro S.A., asociada luego con la Compaâ”śâ–’â”śÂˇa de Alcoholes de Bilbao S.A., a la que absorbiâ”śâ”‚ formando Ebro Compaâ”śâ–’â”śÂˇa de Azâ”śâ•‘cares y Alcoholes, Ecaya. En los aâ”śâ–’os treinta fue Compaâ”śâ–’â”śÂˇa de Alcoholes de Aragâ”śâ”‚n, y en su â”śâ•‘ltima etapa, hasta cerrar en 1971, Alcoholera Ebro S.A. La escena estâ”śĂ­ tomada en el patio de ingreso desde la avenida de San Juan de la Peâ”śâ–’a nâ”¬â•‘ 24-32. A la izquierda, zona de jardines y â”śĂ­rboles. Tras los edificios de la fâ”śĂ­brica de la imagen estaban los depâ”śâ”‚sitos de alcohol y un apartadero propio que conectaba con la red ferroviaria. La lâ”śÂˇnea 4. Arrabal del tranvâ”śÂˇa tenâ”śÂˇa su terminal justo al lado. Tras su clausura, fue derribada, y el entorno profundamente reurbanizado. Fuente visual: "150 aâ”śâ–’os de ferrocarril en Zaragoza", 2011.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20615409492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20615409492.webp', 'https://www.flickr.com/photos/zaragozaantigua/20615409492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22506, 'Av. de Cataluâ”śâ–’a 1960', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 42 de la avenida de Cataluâ”śâ–’a, esquinero con la avenida del Puente del Pilar, y centrada en el ingreso a la fâ”śĂ­brica de Maquinista y Fundiciones del Ebro sita en el nâ”¬â•‘ 17-23 de la avenida de Cataluâ”śâ–’a, con detalle de las modernas naves de caldererâ”śÂˇa y fundiciâ”śâ”‚n de esta factorâ”śÂˇa. Tras ellas despunta la referencial torre de los almacenes de modelos, lindantes con los andenes de la estaciâ”śâ”‚n del Arrabal. En primer tâ”śÂ®rmino, postes de suministro elâ”śÂ®ctrico de los tranvâ”śÂˇas de las lâ”śÂˇneas del Gâ”śĂ­llego y del Barrio de Jesâ”śâ•‘s.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.66040800, -0.86967900, '0101000020E61000005393E00D69D4EBBF2502D53F88D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50325635123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50325635123.webp', 'https://www.flickr.com/photos/zaragozaantigua/50325635123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22550, 'Barrio de La Jota c.1978', 'Vista del Barrio de La Jota, vertebrada en torno a la avenida de Cataluâ”śâ–’a (izquierda). En primer plano, la chimenea y complejo de CLUZASA. Detrâ”śĂ­s de los altos bloques, el extenso Grupo de Viviendas "Parcelaciâ”śâ”‚n Damâ”śĂ­n", asâ”śÂˇ llamadas por el nombre de la constructora que las realizâ”śâ”‚ (Obras y Construcciones Damâ”śĂ­n), con viviendas de una planta con espacio posterior para jardâ”śÂˇn y corral... la "Ciudad Jardâ”śÂˇn" de la Margen Izquierda.', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.66077700, -0.86510800, '0101000020E61000004641F0F8F6AEEBBF79793A5794D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024300906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024300906.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024300906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22553, 'La Azucarera c.1971', 'Con las siglas de la SGAE, Sociedad General Azucarera de Espaâ”śâ–’a, puerta de entrada a la Azucarera del Arrabal. Esta factorâ”śÂˇa transformadora de remolacha, construida en 1893 a espaldas de la homâ”śâ”‚nima estaciâ”śâ”‚n de tren con el nombre de La Azucarera de Aragâ”śâ”‚n, dejâ”śâ”‚ de cumplir su funciâ”śâ”‚n en 1966. Tras la radical transformaciâ”śâ”‚n del edificio y su entorno, esta es la actual calle de las Chimeneas, que confluye a la derecha con la de Mas de las Matas.', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66411600, -0.86810200, '0101000020E61000003DF372D87DC7EBBF0B60CAC001D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15035027551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15035027551.webp', 'https://www.flickr.com/photos/zaragozaantigua/15035027551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22576, 'Valle de Oza 1970', 'Archivo Municipal. Gerardo Sancho Ramo. 1970. Esperando el bus. Imagen de la calle Valle de Oza.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66389500, -0.87533700, '0101000020E6100000F0517FBDC202ECBF2C7DE882FAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428414889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428414889.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428414889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22648, 'Alcalde Caballero 1979', 'Comienzo de las obras de construcciâ”śâ”‚n del colegio pâ”śâ•‘blico La Estrella, en la avenida Alcalde Caballero (abajo). A la derecha, la calle Pedro Lâ”śĂ­zaro. Al fondo, el Pilar y las chimeneas de la Azucarera del Arrabal. Fuente: www.facebook.com/photo.php?fbid=10206445882658631&set...', 1979, 1979, 1979, 'Anos 70', 'EL RABAL', 41.66339700, -0.85795300, '0101000020E6100000AE2990D95974EBBFDCA16131EAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20937137925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20937137925.webp', 'https://www.flickr.com/photos/zaragozaantigua/20937137925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22656, 'CAMPSA c.1975', 'Aâ”śÂ®rea visual de la instalaciâ”śâ”‚n de almacenamiento y distribuciâ”śâ”‚n de gasolina de Campsa, ubicada en 1945 entre la carretera de Huesca y el ferrocarril que llegaba hasta la estaciâ”śâ”‚n del Arrabal. En la imagen y a la izquierda, la avenida de San Juan de la Peâ”śâ–’a, remodelada y asfaltada tras la supresiâ”śâ”‚n de la tranviaria lâ”śÂˇnea 4. Arrabal. A la derecha, vâ”śÂˇas del ferrocarril y Polâ”śÂˇgono Industrial Cogullada. En la parte superior, Hierros Alfonso S.A., la fâ”śĂ­brica de la Uniâ”śâ”‚n Alcoholera Espaâ”śâ–’ola, y la papelera Saica. Poco despuâ”śÂ®s, estos depâ”śâ”‚sitos serâ”śĂ­n desmantelados por razones de seguridad, en cumplimiento de la ordenanza sobre almacenamiento y transporte de productos peligrosos. En 1976, la empresa inaugurarâ”śĂ­ una nueva instalaciâ”śâ”‚n en Monzalbarba. Parte del solar se habilitarâ”śĂ­ para prolongar la calle Marquâ”śÂ®s de la Cadena y dar continuidad a la calle del Valle de Broto.', 1975, 1975, 1975, 'Anos 70', 'EL RABAL', 41.66580500, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFB341261939D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21810662093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21810662093.webp', 'https://www.flickr.com/photos/zaragozaantigua/21810662093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22709, 'San Juan de la Peâ”śâ–’a 1971', 'Imagen del arranque de la calle de San Juan de la Peâ”śâ–’a, con la pareja de unidades de la serie 200 (la 228, de regreso al "centro", y la 223, en direcciâ”śâ”‚n a la terminal de la lâ”śÂˇnea) que entonces prestaban servicio en el tranvâ”śÂˇa del "Arrabal", o Lâ”śÂˇnea 4. A la derecha, muros del antiguo depâ”śâ”‚sito de "Hierros Alfonso S.A.", cuyas traseras eran recayentes a las vâ”śÂˇas del ferrocarril que llegaba a la estaciâ”śâ”‚n del Arrabal, y en el centro, el moderno, pionero y alpino bloque del nâ”¬â•‘ 10 de San Juan de la Peâ”śâ–’a. A la izquierda, fuera de plano, la calle valle de Zuriza, conducente al reciente parque del Tâ”śÂˇo Jorge, antiguo de Jorge Ibort. Apenas dos meses despuâ”śÂ®s de esta imagen, la lâ”śÂˇnea del "Arrabal" fue clausurada. Fuente visual: www.ebay.es/', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66194900, -0.87292900, '0101000020E6100000075C57CC08EFEBBF594FADBEBAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28746247930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28746247930.webp', 'https://www.flickr.com/photos/zaragozaantigua/28746247930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22712, 'San Juan de la Peâ”śâ–’a 1971', 'Imagen de la unidad 223 de la lâ”śÂˇnea 4 del tranvâ”śÂˇa ("Arrabal") regresando a la ciudad desde su norteâ”śâ–’a terminal por la calle de San Juan de la Peâ”śâ–’a, capturada a su paso por las antiguas instalaciones de almacenamiento de la empresa CAMPSA. A la izquierda, fuera de plano, el Grupo de Viviendas "Balsas de Ebro Viejo", y al fondo, tras los depâ”śâ”‚sitos, emergen las pareadas chimeneas de la veterana "Alcoholera". A la derecha, tambiâ”śÂ®n fuera de plano, las vâ”śÂˇas del ferrocarril que conduce a la estaciâ”śâ”‚n "Norte", y el desarrollista polâ”śÂˇgono industrial Cogullada. Este entorno fue luego notablemente modificado, incluyendo la clausura y desmantelamiento del servicio pâ”śâ•‘blico tranviario. Fuente visual: www.ebay.es/', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66566800, -0.87153400, '0101000020E61000001C446B459BE3EBBF32FFE89B34D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29009419816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29009419816.webp', 'https://www.flickr.com/photos/zaragozaantigua/29009419816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22720, 'Estaciâ”śâ”‚n del Norte 1974', 'Imagen de una locomotora a vapor "Mikado" reciâ”śÂ®n salida de la estaciâ”śâ”‚n del Arrabal, en direcciâ”śâ”‚n norte. Al fondo, el complejo de la Maquinista y Fundiciones del Ebro S.A. Estos artefactos estuvieron prestando servicio desde 1953, y hasta 1975, cuando en Espaâ”śâ–’a se dio punto final a la utilizaciâ”śâ”‚n comercial de las locomotoras de vapor. Fuente visual: es.slideshare.net/', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30165423083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30165423083.webp', 'https://www.flickr.com/photos/zaragozaantigua/30165423083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22721, 'Arrabal 1970', 'Imagen de un coche de viajeros tipo "Costa" de la MZA estacionado en una de las vâ”śÂˇas del complejo de la estaciâ”śâ”‚n del Norte. La captura se ha realizado a la altura del gran depâ”śâ”‚sito de locomotoras. A la derecha, nave de los talleres Izuzquiza-Arana, y a la izquierda, chimeneas de la Alcoholera del Ebro. La entrada a ambas instalaciones estaba en la calle de San Juan de la Peâ”śâ–’a, y ambas tenâ”śÂˇan muelle ferroviario. Fuente visual: Foto Josep Ferratâ”śÂ®, en www.spanishrailway.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66327200, -0.87127600, '0101000020E61000003145B9347EE1EBBF1F2DCE18E6D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30186919393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30186919393.webp', 'https://www.flickr.com/photos/zaragozaantigua/30186919393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22732, 'Estaciâ”śâ”‚n Norte 1974', 'Imagen de una vaporosa locomotora "Mikado" maniobrando en el mar de vâ”śÂˇas de la estaciâ”śâ”‚n del Norte. A la derecha, el enorme almacâ”śÂ®n de modelos y la torre de Maquinista y Fundiciones del Ebro, y la pareja de chimeneas de la azucarera del Arrabal. Al fondo, los antiguos talleres, chimenea, y depâ”śâ”‚sito de locomotoras. A la izquierda, enlaces ferroviarios a los muelles de las instalaciones industriales de la zona. La imagen se ha capturado desde el andâ”śÂ®n central de la estaciâ”śâ”‚n, que queda justo a la espalda del fotâ”śâ”‚grafo. Fuente visual: Foto Escudâ”śÂ®, a travâ”śÂ®s de www.forotrenes.com/', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66089100, -0.87165200, '0101000020E610000097C62FBC92E4EBBF419C871398D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31142919896.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31142919896.webp', 'https://www.flickr.com/photos/zaragozaantigua/31142919896/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22764, 'Camino de Juslibol 1978', 'Imagen capturada en un luminoso sector del salvaje oeste del Picarral, en paralelo al antiguo y arbolado camino de Juslibol, donde los grupos de viviendas "Balsas de Ebro Viejo" (inmediato), "Teniente Ortiz de Zâ”śĂ­rate" (detrâ”śĂ­s), y "Teniente Polanco" (a continuaciâ”śâ”‚n). Al fondo, instalaciones de los Talleres Unidos SA, y las traseras de algunos bloques recayentes a la avenida de San Juan de la Peâ”śâ–’a. La acumulaciâ”śâ”‚n de accidentes orogâ”ĽĂ˛â”śĂ­ficos artificiales parece no suponer impedimento serio para la movilidad de los montaraces vecinos del entorno. Tiempo despuâ”śÂ®s, aquâ”śÂˇ se construirâ”śÂˇa el moderno y municipal parque de bomberos nâ”¬â•‘ 1, con entrada principal por Valle de Broto, hasta entonces ubicado provisionalmente en el antiguo cuartel de Pontoneros de Madre Rafols. Fuente visual: Banco de Imâ”śĂ­genes/Asociaciâ”śâ”‚n de Vecinos Barrio de San Josâ”śÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.66782400, -0.87518200, '0101000020E61000002B8881AE7D01ECBFF1BDBF417BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33051240092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33051240092.webp', 'https://www.flickr.com/photos/zaragozaantigua/33051240092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22844, 'CLUZASA 1989', 'Demoliciâ”śâ”‚n de las instalaciones de Cluzasa, Centrales Lecheras Unidas de Zaragoza S.A., donde la calle del Marquâ”śÂ®s de la Cadena intersecciona con las calles de Josâ”śÂ® Oto y del Molino de las Armas, en el barrio de La Jota. Esta empresa lâ”śĂ­ctea habâ”śÂˇa sido fundada en 1956 mediante la uniâ”śâ”‚n de varias granjas dedicadas al reparto del producto a domicilio. Por aquâ”śÂˇ pasarâ”śĂ­ luego el trâ”śĂ­fico rodado del Segundo Cinturâ”śâ”‚n, procedente del puente de la Uniâ”śâ”‚n y de la plaza de Mozart.', 1989, 1989, 1989, 'Anos 80', 'EL RABAL', 41.66096900, -0.86444300, '0101000020E61000003332C85D84A9EBBFBD55D7A19AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15131276905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15131276905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15131276905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22909, 'Marquâ”śÂ®s de la Cadena 1985', 'Ruinas de algunas naves de la empresa de transformaciâ”śâ”‚n metâ”śĂ­lica Hierros Alfonso, con el muro que las separaba a la izquierda de los antiguos depâ”śâ”‚sitos de Campsa y donde en 2007 se inaugurâ”śâ”‚ el Instituto de Educaciâ”śâ”‚n Secundaria La Azucarera, en una industrial zona embuchada entre la avenida de San Juan de la Peâ”śâ–’a y las vâ”śÂˇas del ferrocarril que desde la estaciâ”śâ”‚n del arrabal se dirigâ”śÂˇan a Huesca. Al fondo y la izquierda, esquinero bloque con la calle del Valle de Broto integrado en el Grupo de Viviendas Balsas de Ebro Viejo. La orientaciâ”śâ”‚n de los esqueletos de las naves de primer tâ”śÂ®rmino indica el sentido que aâ”śâ–’os despuâ”śÂ®s seguirâ”śĂ­ la prolongaciâ”śâ”‚n del camino del Marquâ”śÂ®s de la Cadena, cuando desde el Puente de la Uniâ”śâ”‚n conforme aquâ”śÂˇ su â”śâ•‘ltimo tramo dentro del segundo cinturâ”śâ”‚n de ronda. Nuevas y mâ”śĂ­s modernas naves de la misma empresa sustituirâ”śĂ­n a las de la imagen, inmediatas a la factorâ”śÂˇa de Saica. Fuente visual: "Banco de imâ”śĂ­genes del Picarral" (As. de Vecinos del Picarral).', 1985, 1985, 1985, 'Anos 80', 'EL RABAL', 41.66622900, -0.87033200, '0101000020E61000005531957EC2D9EBBFCA52EBFD46D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22444402862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22444402862.webp', 'https://www.flickr.com/photos/zaragozaantigua/22444402862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22922, 'Picarral 1983', 'Panorama del Picarral desde la torre del nuevo Parque de Bomberos de la calle del Valle de Broto. Tras la inmediata calle del Pantano de Yesa, grâ”śâ•‘as de construcciâ”śâ”‚n de los bloques recayentes a la calle Sotonera, y detrâ”śĂ­s el extenso complejo fabril textil de Caitasa, del que emerge su chimenea. A la derecha y tras el camino de Juslibol, la fâ”śĂ­brica de maquinaria pesada Proclain-TUSA, que cesâ”śâ”‚ actividad a finales de 1984 dejando en el paro a sus 424 trabajadores. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66834500, -0.87523500, '0101000020E6100000E010AAD4EC01ECBFFAB836548CD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29674484854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29674484854.webp', 'https://www.flickr.com/photos/zaragozaantigua/29674484854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22923, 'Calle Gracia Gazulla 1983', 'Imagen del antiguo nâ”¬â•‘ 7 de la calle Fernando Gracia Gazulla, edificio propiedad del Ministerio de Obras Pâ”śâ•‘blicas y Urbanismo, que fue la provisional sede del Consejo Municipal de Distrito nâ”¬â•‘ 10, entidad que abarcaba todos los barrios de la margen izquierda del Ebro, y que tras la recuperaciâ”śâ”‚n de la democracia municipal fue el antecedente inmediato de la posterior Junta de Distrito del Rabal. Esta pequeâ”śâ–’a manzana de edificios fue luego derribada, y su espacio incorporado al parque del Tâ”śÂˇo Jorge, antiguo de Jorge Ibort. Fuente visual: revista Nuestra Zaragoza.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66254200, -0.87822900, '0101000020E6100000D7C22CB4731AECBFFC1C1F2DCED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29913294004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29913294004.webp', 'https://www.flickr.com/photos/zaragozaantigua/29913294004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22924, 'Barrionuevo 1983', 'Josâ”śÂ® Barrionuevo Peâ”śâ–’a, ministro del Interior en el primer gobierno del PSOE salido de las elecciones generales de octubre de 1982, en una imagen capturada durante la inauguraciâ”śâ”‚n oficial del nuevo Parque de Bomberos sito en la calle del Valle de Broto, la vâ”śÂˇspera del 23 de abril de ese aâ”śâ–’o. A la izquierda, el alcalde Ramâ”śâ”‚n Sainz de Varanda. Casualmente, en 1983 comenzaron su andadura los parapoliciales y autodenominados Grupos Antiterroristas de Liberaciâ”śâ”‚n, GAL. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66747200, -0.87561100, '0101000020E61000004792205C0105ECBF737FF5B86FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29990562340.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29990562340.webp', 'https://www.flickr.com/photos/zaragozaantigua/29990562340/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22926, 'Salvador Allende 1983', 'Imagen capturada desde la torre del nuevo Parque de Bomberos sito en la calle Valle de Broto, con interesante visual del desarrollo urbanâ”śÂˇstico en la zona delimitada por la Avenida de Salvador Allende, las calles Isla Graciosa, e Isla de Gran Canaria, donde los bloques en construcciâ”śâ”‚n inmediatos, y detrâ”śĂ­s, la calle Violeta Parra, y al fondo, la Avenida de los Pirineos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66847100, -0.87659200, '0101000020E61000006CED7DAA0A0DECBF86A92D7590D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30253047606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30253047606.webp', 'https://www.flickr.com/photos/zaragozaantigua/30253047606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22978, 'Casa Solans aâ”śâ–’os 90', 'La modernista Casa Solans (Miguel â”śĂĽngel Navarro, 1921) en los aâ”śâ–’os 90 del siglo XX, en estado de abandono, con las ventanas tapiadas. Sita en la avenida de Cataluâ”śâ–’a 60. En 2003 comenzâ”śâ”‚ a restaurarse. Posteriormente se ha habilitado como Oficina de Naciones Unidas de apoyo al Decenio del Agua 2005-2015. Fuente: www.facebook.com/ZGZayeryhoy/photos/pcb.1568456450051281/...', 1990, 1990, 1999, 'Anos 90', 'EL RABAL', 41.66079000, -0.86767500, '0101000020E61000004ED1915CFEC3EBBF0DC347C494D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15656696691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15656696691.webp', 'https://www.flickr.com/photos/zaragozaantigua/15656696691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22983, 'Estaciâ”śâ”‚n del Norte 1997', 'Pintura de Eduardo Laborda que captura un paisaje irrepetible de la antigua Zaragoza industrial: la Estaciâ”śâ”‚n del Norte, la "Maquinista y Fundiciones del Ebro" y, al fondo, la pareja de chimeneas que anuncia la Azucarera de Aragâ”śâ”‚n o del Arrabal. La niebla se estâ”śĂ­ echando, y la excavadora anuncia la inminencia de unos cambios que recompondrâ”śĂ­n esta zona de forma muy intensa, fundamentalmente en forma de nuevos bloques de viviendas, anunciados tambiâ”śÂ®n por los que emergen al fondo, en la Avenida de Cataluâ”śâ–’a. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajalâ”śâ”‚n, 2006.', 1997, 1997, 1997, 'Anos 90', 'EL RABAL', 41.66049700, -0.87181400, '0101000020E6100000FB3C4679E6E5EBBF950D6B2A8BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18932311193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18932311193.webp', 'https://www.flickr.com/photos/zaragozaantigua/18932311193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23078, 'Estaciâ”śâ”‚n del Norte c.2000', 'El edificio de la Estaciâ”śâ”‚n del Norte de Zaragoza, con el aspecto que presentaba de abandono hacia el aâ”śâ–’o 2000. En la primera mitad de la dâ”śÂ®cada siguiente, fue rehabilitado como Centro Câ”śÂˇvico. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 2000, 2000, 2000, 'Siglo XXI', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915688505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915688505.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915688505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23962, 'Casa cuartel de la Guardia Civil 1987', 'El 11 de diciembre de 1987, el comando Argala de la organizaciâ”śâ”‚n terrorista ETA, dirigido por Henri Parot, colocâ”śâ”‚ un coche bomba cargado con 250 kilos de amonal en un lateral de la casa cuartel y Comandancia de la Guardia Civil en Zaragoza, donde vivâ”śÂˇan 40 familias de guardiaciviles y 40 estudiantes que preparar su ingreso en el Cuerpo. La explosiâ”śâ”‚n produjo el asesinato de 11 personas y heridas en otras 88, y ademâ”śĂ­s causâ”śâ”‚ el derrumbe parcial del edificio y graves daâ”śâ–’os en los inmuebles de alrededor. En el solar que dejâ”śâ”‚ el posterior derribo del edificio se habilitâ”śâ”‚ luego una plaza denominada Parque de la Esperanza, a la altura del nâ”śâ•‘mero 76 de la avenida de Cataluâ”śâ–’a. En la imagen, capturada en altura desde la calle del Marquâ”śÂ®s de la Cadena, estado de la casa cuartel tras la explosiâ”śâ”‚n, con la calle de Josâ”śÂ® Oto a la izquierda y las chimeneas de la Azucarera del Arrabal al fondo y a la derecha.', 1987, 1987, 1987, 'Anos 80', 'EL RABAL', 41.66155800, -0.86572600, '0101000020E61000002C80290307B4EBBF1E34BBEEADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938457215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938457215.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938457215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23978, 'Fiestas del Pilar 1907', 'Archivo Municipal de Zaragoza. Cartel de las "Fiestas y Ferias a Nuestra Seâ”śâ–’ora del Pilar 1907", Victoriano Balasanz. En la imagen se reproduce el espacio cubierto de los andenes de la Estaciâ”śâ”‚n del Norte en el Arrabal, con vistas a la Seo y el Pilar. La â”śÂ®poca era propicia para representar temas ferroviarios, dado que la implantaciâ”śâ”‚n de los trenes en Europa era signo de modernidad, del mismo modo que lo es ahora arrasar con ellos. Para mâ”śĂ­s informaciâ”śâ”‚n sobre los trayectos ferroviarios abandonados de la ciudad de Zaragoza, ver el documental "Las lâ”śÂˇneas perdidas" (Josâ”śÂ® Marâ”śÂˇa Ballestin y Antonio Tausiet, 2014), pulsando aquâ”śÂˇ: www.youtube.com/watch?v=IOx2B3NQ7zg', 1907, 1907, 1907, 'Anos 1900', 'EL RABAL', 41.65996400, -0.87169400, '0101000020E610000052D2C3D0EAE4EBBFC8444AB379D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15260378959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15260378959.webp', 'https://www.flickr.com/photos/zaragozaantigua/15260378959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24123, 'Av. de Cataluâ”śâ–’a 1987', 'Imagen capturada a la altura del nâ”śâ•‘mero 78 de la avenida de Cataluâ”śâ–’a y centrada en la fachada principal de la casa cuartel de la Guardia Civil allâ”śÂˇ ubicada, tras el atentado de que fue objeto el 11 de diciembre de ese aâ”śâ–’o por parte de la organizaciâ”śâ”‚n terrorista ETA. Esta casa cuartel habâ”śÂˇa sido inaugurada el 12 de noviembre de 1955, y tras este trâ”śĂ­gico atentado fue demolida dejando un solar donde fue proyectado el Parque de la Esperanza. En primer tâ”śÂ®rmino diversos vehâ”śÂˇculos y ambulancias estacionadas ante la casa cuartel. A la izquierda, grâ”śâ•‘a maniobrando en la calle de la Villa de Ruesta donde estallâ”śâ”‚ el coche bomba. A la derecha, el vecino inmueble del nâ”śâ•‘mero 74 de la avenida.', 1987, 1987, 1987, 'Anos 80', 'EL RABAL', 41.66155800, -0.86572600, '0101000020E61000002C80290307B4EBBF1E34BBEEADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54298439145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54298439145.webp', 'https://www.flickr.com/photos/zaragozaantigua/54298439145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
